function applyRows(prods: Product[], trades: any[]) {
    const populated = populateRows(prods, trades);
    setRows(populated);
    const allReadOnly = prods.every((p) => populated[p.id]?.isReadOnly);
    setIsAllReadOnly(allReadOnly);
    setUnlockedIds(new Set());
  }

