    const rawValue = formattedValue.replace(/,/g, '');
    const val = parseFloat(rawValue) || 0;

    setRows((r) => {
      const updated = { ...r[id], [field]: val };
      updated.total_value = updated.price_per_kg * updated.quantity_kg;
      return { ...r, [id]: updated };
    });

    setDisplayValues(prev => ({
